import { useState, useEffect, useRef } from 'react';
import { patientAPI } from '../../utils/api';

export default function NearbyHospitals() {
  const [doctors, setDoctors] = useState([]);
  const [userLocation, setUserLocation] = useState(null);
  const [locationError, setLocationError] = useState('');
  const [selectedDoc, setSelectedDoc] = useState(null);
  const [mapLoaded, setMapLoaded] = useState(false);
  const mapRef = useRef(null);
  const mapInstance = useRef(null);
  const markersRef = useRef([]);

  useEffect(() => {
    patientAPI.getDoctors().then(r => setDoctors(r.data)).catch(() => {});
    getUserLocation();
  }, []);

  useEffect(() => {
    if (!mapLoaded) loadLeaflet();
  }, []);

  useEffect(() => {
    if (mapLoaded && mapRef.current && !mapInstance.current) initMap();
  }, [mapLoaded, userLocation, doctors]);

  const loadLeaflet = () => {
    if (window.L) { setMapLoaded(true); return; }
    const link = document.createElement('link');
    link.rel = 'stylesheet';
    link.href = 'https://unpkg.com/leaflet@1.9.4/dist/leaflet.css';
    document.head.appendChild(link);
    const script = document.createElement('script');
    script.src = 'https://unpkg.com/leaflet@1.9.4/dist/leaflet.js';
    script.onload = () => setMapLoaded(true);
    document.head.appendChild(script);
  };

  const getUserLocation = () => {
    if (!navigator.geolocation) { setLocationError('Geolocation not supported'); return; }
    navigator.geolocation.getCurrentPosition(
      pos => setUserLocation({ lat: pos.coords.latitude, lng: pos.coords.longitude }),
      () => {
        setLocationError('Could not get your location. Showing Jaipur by default.');
        setUserLocation({ lat: 26.9124, lng: 75.7873 });
      }
    );
  };

  const initMap = () => {
    if (!window.L || !mapRef.current) return;
    const L = window.L;
    const center = userLocation ? [userLocation.lat, userLocation.lng] : [26.9124, 75.7873];

    const map = L.map(mapRef.current).setView(center, 13);
    L.tileLayer('https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png', {
      attribution: '© OpenStreetMap contributors'
    }).addTo(map);

    // User marker
    if (userLocation) {
      const userIcon = L.divIcon({
        className: '',
        html: `<div style="width:18px;height:18px;background:#4895ef;border:3px solid white;border-radius:50%;box-shadow:0 2px 8px rgba(0,0,0,0.3)"></div>`,
        iconSize: [18, 18], iconAnchor: [9, 9]
      });
      L.marker([userLocation.lat, userLocation.lng], { icon: userIcon })
        .addTo(map).bindPopup('<strong>📍 Your Location</strong>');
    }

    // Doctor markers
    doctors.forEach(doc => {
      if (!doc.latitude || !doc.longitude) return;
      const icon = L.divIcon({
        className: '',
        html: `<div style="width:36px;height:36px;background:linear-gradient(135deg,#2d6a4f,#40916c);border:2px solid white;border-radius:50%;display:flex;align-items:center;justify-content:center;font-size:16px;box-shadow:0 3px 10px rgba(0,0,0,0.25);cursor:pointer">🏥</div>`,
        iconSize: [36, 36], iconAnchor: [18, 18]
      });
      const marker = L.marker([parseFloat(doc.latitude), parseFloat(doc.longitude)], { icon })
        .addTo(map)
        .bindPopup(`
          <div style="font-family:DM Sans,sans-serif;min-width:200px">
            <strong style="font-size:14px">Dr. ${doc.full_name}</strong><br/>
            <span style="color:#2d6a4f;font-size:12px">${doc.specialization}</span><br/>
            <hr style="margin:6px 0;border:none;border-top:1px solid #eee"/>
            <span style="font-size:12px">🏥 ${doc.hospital_name}</span><br/>
            <span style="font-size:12px">📍 ${doc.hospital_address}</span><br/>
            <span style="font-size:12px">💰 ₹${doc.consultation_fee}</span><br/>
            <span style="font-size:12px">📞 ${doc.phone}</span>
          </div>
        `);
      markersRef.current.push({ marker, doc });
    });

    mapInstance.current = map;
  };

  const focusDoctor = (doc) => {
    setSelectedDoc(doc);
    if (!mapInstance.current || !doc.latitude) return;
    mapInstance.current.setView([parseFloat(doc.latitude), parseFloat(doc.longitude)], 15);
    const found = markersRef.current.find(m => m.doc.id === doc.id);
    if (found) found.marker.openPopup();
  };

  return (
    <div className="animate-fade">
      <div style={{ marginBottom: 24 }}>
        <h1 style={{ fontFamily: 'var(--font-display)', fontSize: 28, marginBottom: 6 }}>🗺️ Nearby Hospitals & Doctors</h1>
        <p style={{ color: 'var(--text-muted)' }}>Find healthcare facilities near you on the map</p>
        {locationError && (
          <div style={{ marginTop: 8, padding: '8px 14px', background: 'var(--warning-light)', borderRadius: 8, fontSize: 13, color: '#b45309' }}>
            ⚠️ {locationError}
          </div>
        )}
      </div>

      <div style={{ display: 'grid', gridTemplateColumns: '300px 1fr', gap: 20 }}>
        {/* Doctor list */}
        <div>
          <div className="card" style={{ height: 480, overflow: 'hidden', display: 'flex', flexDirection: 'column' }}>
            <div className="card-header" style={{ flexShrink: 0 }}>
              <h2>Doctors ({doctors.length})</h2>
            </div>
            <div style={{ overflowY: 'auto', flex: 1 }}>
              {doctors.map(doc => (
                <div key={doc.id}
                  onClick={() => focusDoctor(doc)}
                  style={{
                    padding: '14px 16px',
                    borderBottom: '1px solid var(--border)',
                    cursor: 'pointer',
                    background: selectedDoc?.id === doc.id ? 'var(--success-light)' : 'white',
                    transition: 'background 0.2s',
                  }}>
                  <div style={{ display: 'flex', gap: 10, alignItems: 'center' }}>
                    <div className="doctor-avatar" style={{ width: 38, height: 38, fontSize: 16, flexShrink: 0 }}>
                      {doc.full_name[0]}
                    </div>
                    <div>
                      <div style={{ fontWeight: 600, fontSize: 14 }}>Dr. {doc.full_name}</div>
                      <div style={{ color: 'var(--primary)', fontSize: 12 }}>{doc.specialization}</div>
                      <div style={{ fontSize: 11, color: 'var(--text-muted)', marginTop: 2 }}>
                        🏥 {doc.hospital_name}
                      </div>
                    </div>
                  </div>
                </div>
              ))}
            </div>
          </div>
        </div>

        {/* Map */}
        <div>
          <div ref={mapRef} className="map-container" style={{ height: 480 }} />
          {!mapLoaded && (
            <div style={{ position: 'absolute', display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
              <div className="spinner" />
            </div>
          )}
        </div>
      </div>

      {/* Doctor detail */}
      {selectedDoc && (
        <div className="card animate-slide" style={{ marginTop: 20 }}>
          <div className="card-body">
            <div style={{ display: 'flex', gap: 16, alignItems: 'flex-start', flexWrap: 'wrap' }}>
              <div className="doctor-avatar">{selectedDoc.full_name[0]}</div>
              <div style={{ flex: 1 }}>
                <h3 style={{ fontSize: 18, fontWeight: 700 }}>Dr. {selectedDoc.full_name}</h3>
                <div style={{ color: 'var(--primary)', fontWeight: 500, marginBottom: 4 }}>{selectedDoc.specialization}</div>
                <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(200px, 1fr))', gap: 8, fontSize: 13, color: 'var(--text-muted)' }}>
                  <span>🏥 {selectedDoc.hospital_name}</span>
                  <span>📍 {selectedDoc.hospital_address}</span>
                  <span>📞 {selectedDoc.phone}</span>
                  <span>💰 ₹{selectedDoc.consultation_fee}</span>
                  <span>⏱️ {selectedDoc.experience_years} years experience</span>
                  <span>📅 {selectedDoc.available_days}</span>
                </div>
                {selectedDoc.bio && <p style={{ marginTop: 8, fontSize: 13, color: 'var(--text-muted)' }}>{selectedDoc.bio}</p>}
              </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}
